import type { Metadata } from "next"
import PropertyManagement from "./PropertyManagement"

export const metadata: Metadata = {
  title: "物件管理 / レントロール | ぐんじょう管理",
  description:
    "賃貸管理会社向けの物件管理・レントロール画面。管理物件ごとの入居率（入居戸数 / 総戸数）、部屋単位のレントロール（契約者・賃料＋管理費・敷金礼金・契約期間・状態）、月間賃料収入、滞納状況（滞納月数・滞納額・督促・経過月数別エイジング）、契約更新・退去予定（契約満了60日以内）を一覧で管理。空室は募集中として表示し、各種アクション（契約更新・退去処理・督促記録・募集開始・CSVエクスポート）を備えたポートフォリオ管理ツール。",
}

export default function PropertyManagementPage() {
  return <PropertyManagement />
}

// 物件管理 / レントロール — domain model + derivations (pure, SSR-safe).
// 賃貸管理会社 が portfolio を見渡すための型と計算。すべての数字はここで一貫させる。

export type UnitStatus = "occupied" | "vacant" | "moving-out" | "arrears"

export interface Unit {
  /** 部屋番号 e.g. "101" */
  roomNo: string
  /** 間取り 1K / 1LDK / 2LDK … */
  layout: string
  /** 専有面積 (㎡) */
  areaSqm: number
  /** 契約者。空室は null。 */
  tenant: string | null
  /** 月額賃料 (¥) */
  rent: number
  /** 月額管理費・共益費 (¥) */
  maintenance: number
  /** 敷金 (ヶ月) */
  depositMonths: number
  /** 礼金 (ヶ月) */
  keyMoneyMonths: number
  /** 契約開始日 ISO (空室は null) */
  leaseStart: string | null
  /** 契約満了日 ISO (空室は null) */
  leaseEnd: string | null
  /** 滞納月数 (0 = 滞納なし) */
  arrearsMonths: number
  /** この入居者の意向: 満了時に更新するか退去するか (occupied のみ意味を持つ) */
  intent?: "renew" | "move-out" | undefined
  /** 督促状況 (滞納時) */
  dunningStatus?: string
}

export interface Building {
  id: string
  name: string
  address: string
  /** 構造 RC / SRC / 木造 / 鉄骨 */
  structure: string
  /** 築年 (西暦) */
  builtYear: number
  units: Unit[]
}

// ────────────────────────────────────────────────────────────────────────────
// Derivations — single source of truth; summary / building / unit all reconcile.
// ────────────────────────────────────────────────────────────────────────────

// derive a discrete status for display from the raw fields.
// 滞納・退去予定も契約は生きているので「占有」扱い (賃料収入は立つ)。
export function unitStatus(u: Unit): UnitStatus {
  if (u.tenant == null) return "vacant"
  if (u.arrearsMonths > 0) return "arrears"
  if (u.intent === "move-out") return "moving-out"
  return "occupied"
}

// occupancy counts a unit as occupied iff it has a tenant (滞納・退去予定も契約継続中)
export function buildingOccupiedCount(b: Building): number {
  return b.units.filter((u) => u.tenant != null).length
}

export function buildingTotalUnits(b: Building): number {
  return b.units.length
}

/** 入居率 = 入居戸数 / 総戸数 (0–1, clamped). */
export function occupancyRatio(occupied: number, total: number): number {
  if (total <= 0) return 0
  return Math.min(1, Math.max(0, occupied / total))
}

/** 月額賃料合計 = Σ 入居中部屋の (賃料 + 管理費)。空室は計上しない。 */
export function buildingMonthlyIncome(b: Building): number {
  return b.units
    .filter((u) => u.tenant != null)
    .reduce((sum, u) => sum + u.rent + u.maintenance, 0)
}

/** 満室時の potential 賃料合計 (空室含む) — 機会損失の把握用。 */
export function buildingPotentialIncome(b: Building): number {
  return b.units.reduce((sum, u) => sum + u.rent + u.maintenance, 0)
}

export function buildingArrearsTotal(b: Building): number {
  return b.units
    .filter((u) => u.arrearsMonths > 0)
    .reduce((sum, u) => sum + (u.rent + u.maintenance) * u.arrearsMonths, 0)
}

export function buildingArrearsCount(b: Building): number {
  return b.units.filter((u) => u.arrearsMonths > 0).length
}

/** 単一部屋の滞納額。 */
export function unitArrearsAmount(u: Unit): number {
  return (u.rent + u.maintenance) * u.arrearsMonths
}

// ── Portfolio-level rollups ──────────────────────────────────────────────────

export interface PortfolioSummary {
  buildingCount: number
  totalUnits: number
  occupiedUnits: number
  occupancyRatio: number
  monthlyIncome: number
  potentialIncome: number
  arrearsTotal: number
  arrearsCount: number
  /** 今月満了で更新意向の戸数 */
  renewalsDue: number
  /** 今月満了で退去意向の戸数 */
  moveOutsDue: number
}

export function summarize(buildings: Building[], today: Date, windowDays = 60): PortfolioSummary {
  let totalUnits = 0
  let occupiedUnits = 0
  let monthlyIncome = 0
  let potentialIncome = 0
  let arrearsTotal = 0
  let arrearsCount = 0
  let renewalsDue = 0
  let moveOutsDue = 0

  for (const b of buildings) {
    totalUnits += buildingTotalUnits(b)
    occupiedUnits += buildingOccupiedCount(b)
    monthlyIncome += buildingMonthlyIncome(b)
    potentialIncome += buildingPotentialIncome(b)
    arrearsTotal += buildingArrearsTotal(b)
    arrearsCount += buildingArrearsCount(b)
    for (const u of upcomingLeaseEnds(b, today, windowDays)) {
      if (u.intent === "move-out") moveOutsDue += 1
      else renewalsDue += 1
    }
  }

  return {
    buildingCount: buildings.length,
    totalUnits,
    occupiedUnits,
    occupancyRatio: occupancyRatio(occupiedUnits, totalUnits),
    monthlyIncome,
    potentialIncome,
    arrearsTotal,
    arrearsCount,
    renewalsDue,
    moveOutsDue,
  }
}

// ── Renewals / move-outs window ──────────────────────────────────────────────

export function daysUntil(iso: string, today: Date): number {
  const end = new Date(iso + "T00:00:00")
  const start = new Date(today.getFullYear(), today.getMonth(), today.getDate())
  return Math.round((end.getTime() - start.getTime()) / 86_400_000)
}

/** 契約満了が today から windowDays 以内の occupied 部屋 (期日昇順)。 */
export function upcomingLeaseEnds(b: Building, today: Date, windowDays: number): Unit[] {
  return b.units
    .filter((u) => u.tenant != null && u.leaseEnd != null)
    .filter((u) => {
      const d = daysUntil(u.leaseEnd as string, today)
      return d >= 0 && d <= windowDays
    })
    .sort((a, b2) => daysUntil(a.leaseEnd as string, today) - daysUntil(b2.leaseEnd as string, today))
}

export interface UpcomingRow {
  buildingName: string
  unit: Unit
  days: number
}

export function allUpcoming(buildings: Building[], today: Date, windowDays: number): UpcomingRow[] {
  const rows: UpcomingRow[] = []
  for (const b of buildings) {
    for (const u of upcomingLeaseEnds(b, today, windowDays)) {
      rows.push({ buildingName: b.name, unit: u, days: daysUntil(u.leaseEnd as string, today) })
    }
  }
  return rows.sort((a, b) => a.days - b.days)
}

// ── Arrears (滞納) aging ──────────────────────────────────────────────────────

export type ArrearsBucket = "1" | "2" | "3plus"

export function arrearsBucket(months: number): ArrearsBucket {
  if (months >= 3) return "3plus"
  if (months >= 2) return "2"
  return "1"
}

export interface ArrearsRow {
  buildingName: string
  unit: Unit
  amount: number
  bucket: ArrearsBucket
}

export function allArrears(buildings: Building[]): ArrearsRow[] {
  const rows: ArrearsRow[] = []
  for (const b of buildings) {
    for (const u of b.units) {
      if (u.arrearsMonths > 0) {
        rows.push({
          buildingName: b.name,
          unit: u,
          amount: unitArrearsAmount(u),
          bucket: arrearsBucket(u.arrearsMonths),
        })
      }
    }
  }
  // 重い滞納 (月数多い) を上に
  return rows.sort((a, b) => b.unit.arrearsMonths - a.unit.arrearsMonths)
}

export interface ArrearsAging {
  oneMonth: { count: number; amount: number }
  twoMonth: { count: number; amount: number }
  threePlus: { count: number; amount: number }
}

export function arrearsAging(rows: ArrearsRow[]): ArrearsAging {
  const agg: ArrearsAging = {
    oneMonth: { count: 0, amount: 0 },
    twoMonth: { count: 0, amount: 0 },
    threePlus: { count: 0, amount: 0 },
  }
  for (const r of rows) {
    const slot = r.bucket === "3plus" ? agg.threePlus : r.bucket === "2" ? agg.twoMonth : agg.oneMonth
    slot.count += 1
    slot.amount += r.amount
  }
  return agg
}
